const name = $('Form - إدخال البيانات').item.json['الاسم'];
const feedback = $('Form - إدخال البيانات').item.json['الفيدباك عن الدورة'];
const aiResponse = $input.item.json.message.content;

let result;
try {
  result = JSON.parse(aiResponse);
} catch(e) {
  result = { 'التصنيف': 'غير محدد', 'السبب': aiResponse, 'نقاط_مميزة': '-' };
}

return {
  الاسم: name,
  الفيدباك: feedback,
  التصنيف: result['التصنيف'],
  السبب: result['السبب'],
  نقاط_مميزة: result['نقاط_مميزة'],
  الوقت: new Date().toLocaleString('ar-SA')
};

