=<!DOCTYPE html>
<html dir="rtl" lang="ar">
<head>
  <meta charset="UTF-8">
  <title>نتيجة التقييم</title>
  <style>
    body { font-family: Arial, sans-serif; display:flex; justify-content:center; align-items:center; min-height:100vh; margin:0; background:#f0f4f8; }
    .card { background:white; padding:40px; border-radius:16px; box-shadow:0 4px 20px rgba(0,0,0,0.1); max-width:500px; width:90%; text-align:center; }
    .badge { display:inline-block; padding:10px 30px; border-radius:50px; font-size:24px; font-weight:bold; margin:20px 0; }
    .smart { background:#d4edda; color:#155724; border:2px solid #28a745; }
    .dumb  { background:#f8d7da; color:#721c24; border:2px solid #dc3545; }
    .reason { background:#f8f9fa; padding:15px; border-radius:8px; margin:15px 0; color:#555; }
    h2 { color:#333; margin-bottom:5px; }
    .name { color:#007bff; font-size:20px; font-weight:bold; }
  </style>
</head>
<body>
  <div class="card">
    <h2>نتيجة تقييم الفيدباك</h2>
    <p>شكراً <span class="name">{{ $json.الاسم }}</span>!</p>
    <div class="badge {{ $json.التصنيف === 'ذكي' ? 'smart' : 'dumb' }}">
      {{ $json.التصنيف === 'ذكي' ? '🧠 فيدباك ذكي' : '💤 فيدباك غير مفيد' }}
    </div>
    <div class="reason">
      <strong>السبب:</strong> {{ $json.السبب }}
    </div>
    <p><strong>أبرز نقطة:</strong> {{ $json['نقاط_مميزة'] }}</p>
    <small style="color:#999">{{ $json.الوقت }}</small>
  </div>
</body>
</html>
